BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?val ?valName ?valType WHERE {
  ?req vocab:NamedElement_name "High%20signal%20exposures" .
  ?req vocab:Element__elementValueOfElement ?val .
  ?val vocab:NamedElement_name ?valName .
  OPTIONAL { ?val rdf:type ?valType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?name WHERE {
  ?dep rdf:type vocab:dependency .
  OPTIONAL { ?dep vocab:NamedElement_name ?name }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
